head.script:
// scwin.menuList;
scwin.strCurDate;
scwin.nowDt;
scwin.nextDt;

scwin.MSG_OP_INF_001 = "Booking 내역의 오더번호를 지정하십시오.";
scwin.MSG_OP_INF_002 = "Booking 번호를 입력하세요.";
scwin.MSG_OP_INF_003 = "오더 번호가 이미 지정이 되어 있습니다.";
scwin.MSG_OP_INF_004 = "승인구분이 오류일 경우에만 조회가능합나다.";
scwin.MSG_OP_INF_005 = "오류인 경우 '선택/확인' 버튼을 이용하여 주십시오.";
scwin.MSG_OP_INF_006 = "오더가 생성되었습니다.";
//scwin.MSG_OP_INF_007 = "저장버튼을 눌러 오더를 삭제하시기 바랍니다.";
scwin.MSG_OP_ERR_011 = "해당 요청건은 접수 또는 오류처리만 가능한 요청입니다.";

scwin.MSG_OP_ERR_001 = "오더번호는 이미 생성되어 있습니다";
scwin.MSG_OP_ERR_002 = "수출상차 요청 승인 내역이 없어, 오더를 생성할 수 없습니다";
scwin.MSG_OP_ERR_003 = "승인 구분이 %1인 경우만 가능합니다.";
scwin.MSG_OP_ERR_004 = "오더 번호가 존재하지 않습니다. 오더 번호를 확인 하세요.";
scwin.MSG_OP_ERR_005 = "승인구분 상태가 @가 아닙니다. 계속 진행하시겠습니까?";
scwin.MSG_OP_CFM_001 = "승인을 취소하시겠습니까?";

scwin.MSG_OP_INF_008 = "승인취소 후, 오류 처리 하세요. ";

scwin.bf_admitClsCd = "";

/**
 * event
 * @name onpageload
 * @description 화면로딩시
 */
scwin.onpageload = function () {
    // scwin.menuList = ["규격별 상차 승인 내역", "컨테이너별 상차 승인 내역"];

    scwin.strCurDate = $c.date.getServerDateTime("yyyyMMdd");
    scwin.nowDt = scwin.strCurDate;
    scwin.nextDt = $c.date.addDate(scwin.nowDt, 1);

    const codeOptions = [
        { grpCd: "OP179", compID: "acb_admitClsCd" },   // 접수구분
        { grpCd: "SD215", compID: "acb_jeVanTermCd,acb_liVanTermCd" },
    ];
    $c.data.setCommonCode(codeOptions, scwin.onLoadCommonCode);

    gr_exportOnRequest.setUserData("gridName", "수출 상차 요청 승인");
};

/**
 * event
 * @name onUdcCompleted
 * @description
 */
scwin.onUdcCompleted = async function () {
    ed_srchSelfTransCoCd.options.fixLength = "6";

    let param = $c.data.getParameter();
    if ($c.util.isJSON(param.pgmInfo)) {
        param = param.pgmInfo;
    }

    dma_condition.set("selfTransClntNo", param.selfTransClntNo ?? "");   // 자가운송사
    dma_condition.set("onReqNo", param.onReqNo ?? "");                   // 상차요청번호
    ed_txt_srchSelfTransCoCd.setValue(param.selfTransClntNm ?? "");         // 자가운송사명
    ed_srchSelfTransCoCd.focus();

    $c.gus.cfDisableObjects([ed_bookingNo, rd_dpctYn]);

    const condition = dma_condition.getJSON();
    if (condition.onReqNo == "" && condition.selfTransClntNo == "") {
        tbx_admitClsCd.setValue("승인구분");
        return;
    }
    ed_srchSelfTransCoCd.options.hidVal = condition.selfTransClntNo;
    await scwin.f_Retrieve();

    let retrieve = ds_retrieve.getRowJSON(0);
    if (retrieve.lineCd == "SKR") {
        tbx_admitClsCd.setValue("승인구분/선수납");
        acb_admitClsCd2.show("");
    } else {
        tbx_admitClsCd.setValue("승인구분");
        acb_admitClsCd2.hide();
    }

    if (condition.selfTransClntNo != "" || condition.onReqNo != "") {
        await scwin.f_Retrieve();
    }

    //규격 Look up
    dma_retrieveExportCommCd.setJSON({
        sysCd: "OnRequestAdmissionEBC",
        queryId: "retrieveExportCommCd",
        param1: condition.selfTransClntNo,
        param2: retrieve.onReqNo,
    });
    await $c.sbm.execute(sbm_retrieveExportCommCd);
};

/**
 * method
 * @name onLoadCommonCode
 * @description 공통코드 조회 콜백
 */
scwin.onLoadCommonCode = function () {
    let matched = dlt_commonCodeOP179.getMatchedIndex("cd", "A", true);
    if (matched.length) {
        dlt_commonCodeOP179.removeRows(matched);
    }
};

/**
 * method
 * @name f_Retrieve
 * @description 조회
 */
scwin.f_Retrieve = async function () {
    if ($c.gus.cfIsNull(ed_srchSelfTransCoCd.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["자가운송사"]);
        ed_srchSelfTransCoCd.focus();
        return;
    }
    if ($c.gus.cfIsNull(ed_srchOnReqNo.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["상차 요청 번호"]);
        ed_srchOnReqNo.focus();
        return;
    }

    dma_condition.setJSON({
        "selfTransClntNo": ed_srchSelfTransCoCd.getValue().trim(),
        "onReqNo": ed_srchOnReqNo.getValue().trim(),
        "impExpClsCd": "O", //수출입구분
        "stDt": "00010101",
        "endDt": "99991231",
        "gubun": "",
    });

    $c.sbm.execute(sbm_retrieve);
};

/**
 * method
 * @name f_FieldClear
 * @description 조회 조건 초기화
 */
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects([ed_srchSelfTransCoCd, ed_txt_srchSelfTransCoCd, ed_srchOnReqNo]);
};

/**
 * method
 * @name f_Save
 * @description 저장
 */
scwin.f_Save = async function () {
    let retrieve = ds_retrieve.getRowJSON(0);
    if (!await scwin.f_prefareCheck()) {
        return;
    }

    ds_retrieve.setCellData(0, "vsslCd", ed_vsslCd.getValue());
    ds_retrieve.setCellData(0, "vsslNm", ed_vsslNm.getValue());
    ds_retrieve.setCellData(0, "portcnt", ed_portcnt.getValue());

    if (acb_admitClsCd2.getValue() == "Y") {
        ds_retrieve.setCellData(0, "prebilgYn", 1);
    } else if (acb_admitClsCd2.getValue() == "N") {
        ds_retrieve.setCellData(0, "prebilgYn", 0);
    }

    if (retrieve.lineCd == "WJS" && retrieve.odrNo.substring(1, 3) == "C6") {
        if (retrieve.jeVanTerm != retrieve.liVanTerm) {
            await $c.win.alert("VANTERM이 일치하지 않습니다");
            return false;
        }
    }

    if ($c.gus.cfIsNull(retrieve.odrNo)) {
        if (retrieve.lineCd == "SKR" && $c.gus.cfIsNull(acb_admitClsCd2.getValue())) {
            await $c.win.alert("SKR라인 수출상차요청 승인시에는 반드시 선수납 대상 여부를 기재해야 합니다.");
            return false;
        }
    }
    $c.sbm.execute(sbm_saveExportOnRequest);
};

/**
 * method
 * @name f_prefareCheck
 * @description 저장 전 디폴트값 Check
 */
scwin.f_prefareCheck = async function () {
    if (!await $c.gus.cfValidate([gr_exportOnRequest])) {
        return false;
    }

    let retrieve = ds_retrieve.getRowJSON(0);
    if (retrieve.admitClsCd == "E") {
        await $c.gus.cfAlertMsg(scwin.MSG_OP_INF_005);
        return false;
    }

    if ((retrieve.lineCd == "WHL" || retrieve.lineCd == "IAL") &&
        retrieve.lane != "KSI" &&
        (retrieve.admitClsCd != 'R' && retrieve.admitClsCd != 'E')) {
        await $c.gus.cfAlertMsg(scwin.MSG_OP_ERR_011);
    }

    for (let i = 0; i < ds_ExportOnRequest.getRowCount(); ++i) {
        ds_ExportOnRequest.setCellData(i, "chkFlg", "T");
    }
    return true;
};

/**
 * method
 * @name f_openCommonPopUp
 * @description 조회 팝업
 */
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
    // 선언부
    switch (disGubun) {
        case 1:
            // 자가운송사 Popup   retrieveSelfClnt
            udc_srchSelfTransCoCd.cfCommonPopUp(scwin.udc_srchSelfTransCoCd_popup_callback, pCode, pName, "T", null, null, null, null, ",LOGISCLNT2", null, null, null, null);
            break;

        case 4:
            // 선박 Popup   retrieveVsslCdInfo
            udc_vsslCd.cfCommonPopUp(scwin.udc_vsslCode_popup_callback, pCode, pName, "T", null, null, null, null, null, null, null, null, null, null, null, null, 'F', "선박, 코드, 코드명");
            break;
    }
};

/**
 * method
 * @name udc_srchSelfTransCoCd_popup_callback
 * @description 팝업 콜백
 * @param {Array} rtnList
 */
scwin.udc_srchSelfTransCoCd_popup_callback = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_srchSelfTransCoCd, ed_txt_srchSelfTransCoCd);
};

/**
 * method
 * @name udc_vsslCode_popup_callback
 * @description 팝업 콜백
 * @param {Array} rtnList
 */
scwin.udc_vsslCode_popup_callback = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_vsslCd, ed_vsslNm);
};

/**
 * method
 * @name f_chkOpenCommonPopUpText
 * @description TEXT BOX 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
 */
scwin.f_chkOpenCommonPopUpText = function (inObj, codeObj, disGubun) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.  //inObj.getValue().trim() == "" ||
    if (inObj.getReadOnly() || (inObj.getValue() == inObj.options.hidVal)) {
        return;
    }

    if (codeObj != null) {
        codeObj.setValue("");
        codeObj.options.hidVal = "";
    }

    scwin.f_openCommonPopUp(disGubun, "", inObj.getValue(), 'T', 'T');
};

/**
 * method
 * @name f_chkOpenCommonPopUpEmEdit
 * @description EMEDIT 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
 */
scwin.f_chkOpenCommonPopUpEmEdit = function (inObj, chkObj, txtObj, disGubun) {
    // 해당 EMEDIT가 Disable 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, chkObj)) {
        return;
    }

    if (txtObj != null) {
        txtObj.setValue("");
        txtObj.options.hidVal = "";
    }

    const pCode = inObj.getValue().replace(/^\s*/, '');
    // 값이 입력이 안된 경우  팝업을 실행하지 않음.
    if (pCode == "" || pCode == null) {
        inObj.setValue("");
        chkObj.setValue("");
        return;
    }

    const pName = "";
    scwin.f_openCommonPopUp(disGubun, pCode, pName, 'T', 'T');
};

/**
 * method
 * @name f_orderDetail
 * @description
 */
scwin.f_orderDetail = function () {
    if (!ds_retrieve.getRowCount()) {
        return;
    }
    const v_odrNo = ds_retrieve.getCellData(0, "odrNo");
    if ($c.gus.cfIsNull(v_odrNo)) {
        return;
    }

    let param = {
        "odrNo": v_odrNo,
        "type": "retrieve",
    };

    $c.win.openMenu("컨테이너오더", "/ui/ds/sd/odrmgnt/odrreg/sd_402_01_11t.xml", "sd_402_01_11t", param, { openAction: "exist" });
};

/**
 * method
 * @name f_masterKeyDetail
 * @description
 */
scwin.f_masterKeyDetail = function () {
    if (!ds_retrieve.getRowCount()) {
        return;
    }
    let retrieve = ds_retrieve.getRowJSON(0);
    if ($c.gus.cfIsNull(retrieve.masterKey)) {
        return;
    }

    let param = {
        "wrkPlCd": "",
        "useYn": "1",
        "masterKey": retrieve.masterKey,
    };
    if (retrieve.pickuprgnCd === "EWY") {
        param.wrkPlCd = "4C02";
    } else if (retrieve.pickuprgnCd === "INC") {
        param.wrkPlCd = "4C01";
    } else if (retrieve.pickuprgnCd === "BUG") {
        param.wrkPlCd = "3C01";
    }

    $c.win.openMenu("에버그린마스터키관리", "/ui/ds/sd/odrmgnt/odrreg/sd_402_03_01b.xml", "sd_402_03_01b", param, { openAction: "exist" });//TODO 프로그램 목록에 없음 확인필요
};

/**
 * method
 * @name f_onReqNo
 * @description
 */
scwin.f_onReqNo = function () {
    if (!ds_retrieve.getRowCount()) {
        return;
    }

    let param = {
        "selfTransClntNo": ed_srchSelfTransCoCd.getValue(),
        "selfTransClntNm": ed_txt_srchSelfTransCoCd.getValue(),
        "impExpClsCd": "1",
        "onReqNo": ds_retrieve.getCellData(0, "onReqNo"),
    };

    $c.win.openMenu("수입/수출 상차요청 등록(협력업체)", "/ui/ds/op/wrkrslts/cywrkrslts/op_301_02_01b.xml", "op_301_02_01b", param, { openAction: "exist" });
};

/**
 * method
 * @name f_order
 * @description
 */
scwin.f_order = function () {
    // 선택된 오더 정보 : 오더번호 , flag
    let param = {
        "odrNo": ds_retrieve.getCellData(0, "odrNo"),
        "outIntendNo": "",
    };

    $c.win.openMenu("컨테이너출고예정(선수납)", "/ui/ds/sd/odrmgnt/odroutintend/sd_404_01_02b.xml", "sd_404_01_02b", param, { openAction: "exist" });
};

/**
 * method
 * @name f_OnRequestGoods
 * @description
 */
scwin.f_OnRequestGoods = function () {
    let data = {
        param: `${dma_condition.get('selfTransClntNo')};${dma_condition.get('onReqNo')};"op_301_02_05b"`
    };
    let opts = {
        id: "op_301_02_04p1_popup",
        popupName: "상차요청 및 승인 반출 현황",
        modal: true,
        type: "browserPopup",  //화면 오픈 타입 ("pageFramePopup", "browserPopup")
        title: "Win pop",  //Layer pop
        width: 500,
        height: 540,
    };
    $c.win.openPopup("/ui/ds/op/wrkrslts/cywrkrslts/op_301_02_04p1.xml", opts, data);
};

/**
 * method
 * @name f_limitCnt
 * @description
 */
scwin.f_limitCnt = async function (row) {
    let data = ds_ExportOnRequest.getAllJSON();
    let rowObj = data[row];
    dma_conditionCnt.set("odrNo", ds_retrieve.getCellData(0, 'odrNo'));
    dma_conditionCnt.set("cntrSizCd", rowObj.nrm.substring(0, 2));
    dma_conditionCnt.set("cntrTypCd", rowObj.nrm.substring(2, 4));

    await $c.sbm.execute(sbm_retreiveCnt);

    let qtyCnt = data.filter((item) => item.nrm == rowObj.nrm).reduce((sum, item) => { return sum + $c.num.parseInt(item.admitCnt); }, 0);
    if ($c.num.parseInt(ds_retrieveCnt.getCellData(0, "cnt")) < qtyCnt) {
        await $c.gus.cfAlertMsg("요청수량이 요청 가능수량보다 큽니다.");
        ds_ExportOnRequest.setCellData(row, "admitCnt", 0);
        return false;
    }
};

/**
 * method
 * @name f_ResultsExcel
 * @description 엑셀파일로 저장
 */
scwin.f_ResultsExcel = function () {
    $c.data.downloadGridViewExcel(gr_exportOnRequest, { fileName: "규격별상차승인내역.xlsx", sheetName: "규격별상차승인내역" });
};

/**
 * method
 * @name f_get_cntrCntForMasterKey
 * @description 마스터키 관련정보 조회
 */
scwin.f_get_cntrCntForMasterKey = async function () {
    let odrCntrCnt = ds_ExportOnRequest.getRowCount();	//현재 오더의 컨테이너 개수
    if (odrCntrCnt == 0) {
        return true;
    }

    const retrieve = ds_retrieve.getRowJSON(0);
    if ($c.gus.cfIsNull(retrieve.masterKey)) {
        return true;
    }

    let brnCd = "";
    if (retrieve.pickuprgnCd == "EWY") {
        brnCd = "4BB";
    } else if (retrieve.pickuprgnCd == "INC") {
        brnCd = "4AA";
    } else if (retrieve.pickuprgnCd == "BUG") {
        brnCd = "3BB";
    }

    if ($c.gus.cfIsNull(brnCd)) {
        return true;
    }

    let tmpCntrSiz = "";
    let tmpCntrTyp = "";
    let regCnt = "0";	//오더의 컨테이너 등록개수
    let useCnt = "0"; //반출개수
    let usableCnt = "0";	//주당 반출가능 개수
    for (let i = 0; i < odrCntrCnt; ++i) {
        const nrm = ds_ExportOnRequest.getCellData(i, "nrm");
        const cntrSiz = nrm.substring(0, 2);
        const cntrTyp = nrm.substring(2, 4);

        if (cntrSiz != tmpCntrSiz && cntrTyp != tmpCntrTyp) {
            ds_masterKeyInfo.removeAll();
            dma_retrieveExportCommCd.setJSON({
                sysCd: "CommonEBC",
                queryId: "retrieveMasterKeyInfo",
                param1: brnCd,      // 점소
                param2: retrieve.masterKey,  // 마스터키
                param3: cntrSiz,    // cntr size
                param4: cntrTyp,    // cntr type
            });
            await $c.sbm.execute(sbm_retrieveMasterKeyInfo);

            let masterKeyInfo = ds_masterKeyInfo.getRowJSON(0);
            if (!$c.gus.cfIsNull(masterKeyInfo.col1)) {
                regCnt = masterKeyInfo.col1;	//등록개수
                useCnt = masterKeyInfo.col2;	//반출개수
                usableCnt = masterKeyInfo.col3;	//주당 반출가능 개수
            } else {
                await $c.win.alert("요청한 마스터키의 SIZE/TYPE이 올바르지 않습니다.\n\n 위에 마스터키를 클릭하셔서 확인바랍니다.");
                return false;
            }

            tmpCntrSiz = cntrSiz;
            tmpCntrTyp = cntrTyp;

            await $c.win.alert("마스터키 : " + retrieve.masterKey + "  (" + cntrSiz + "/" + cntrTyp + ")" + "\n\n" +
                "이번주 등록된 컨테이너 개수 : " + regCnt + "개\n\n" +
                "이번주 반출 개수 : " + useCnt + "개\n\n" +
                "주당 반출가능 개수 : " + usableCnt + "개"
            );

            if ($c.num.parseInt(usableCnt) < $c.num.parseInt(useCnt) + $c.num.parseInt(odrCntrCnt)) {
                if (await $c.win.confirm("반출가능 소진개수를 초과했습니다. 오더승인을 진행하시겠습니까?")) {
                    return true;	//초과이지만 확인후 진행
                } else {
                    return false;
                }
            } else {
                return true;	//가능하므로 진행
            }
        }
    }
    return false;
};

/**
 * method
 * @name f_CreateOrder
 * @description
 */
scwin.f_CreateOrder = async function () {
    if (!ds_retrieve.getRowCount()) {
        return;
    }

    if (!await $c.gus.cfValidate([gr_exportOnRequest])) {
        return;
    }

    let retrieve = ds_retrieve.getRowJSON(0);
    if (retrieve.odrNo != "") {
        await $c.gus.cfAlertMsg(scwin.MSG_OP_ERR_001);
        return;
    }

    if (ds_ExportOnRequest.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(scwin.MSG_OP_ERR_002);
        return;
    }

    if (retrieve.admitClsCd != "O" && retrieve.admitClsCd != "R") {
        await $c.gus.cfAlertMsg(scwin.MSG_OP_ERR_003, ["승인 또는 접수"]);
        return;
    }

    if (acb_admitClsCd2.getValue() == 'Y') {
        ds_retrieve.setCellData(0, "prebilgYn", 1);
    } else {
        ds_retrieve.setCellData(0, "prebilgYn", 0);
    }

    if (retrieve.lineCd == "WJS" && $c.gus.cfIsNull(tbx_odrNo.getValue())) {
        if (retrieve.jeVanTerm != acb_liVanTermCd.getValue()) {
            await $c.win.alert("VANTERM이 일치하지 않습니다.");
            return;
        } else {
            ds_retrieve.setCellData(0, "liVanTerm", acb_liVanTermCd.getValue());
        }
    }

    if ($c.gus.cfIsNull(retrieve.odrNo)) {
        if (retrieve.lineCd == "SKR" && $c.gus.cfIsNull(acb_admitClsCd2.getValue())) {
            await $c.win.alert("SKR라인 수출상차요청 승인시에는 반드시 선수납 대상 여부를 기재해야 합니다.");
            return;
        }
    }

    if (!await scwin.f_get_cntrCntForMasterKey()) {
        return;
    }

    $c.sbm.execute(sbm_createExportGeneralOrder);
};

/**
 * method
 * @name f_ErrorCode
 * @description
 */
scwin.f_ErrorCode = async function () {
    let retrieve = ds_retrieve.getRowJSON(0);
    if (retrieve.admitClsCd != 'E') {
        const msg = scwin.MSG_OP_ERR_005.replace("@", "오류"); 98
        if (!await $c.win.confirm(msg)) {
            return;
        }
    }

    if (!$c.gus.cfIsNull(retrieve.odrNo)) {
        await $c.gus.cfAlertMsg(scwin.MSG_OP_INF_008);
        return;
    }

    let data = {
        param: `${retrieve.selfTransClntNo};${retrieve.onReqNo};${retrieve.admitClsCd};op_301_02_04b;${scwin.bf_admitClsCd};${retrieve.lineCd}`
    };
    let opts = {
        id: "op_301_02_03p_popup",
        popupName: "오류 사유 선택",
        modal: true,
        type: "browserPopup",  //화면 오픈 타입 ("pageFramePopup", "browserPopup")
        title: "Win pop",  //Layer pop
        width: 600,
        height: 550,
    };
    let result = await $c.win.openPopup("/ui/ds/op/wrkrslts/cywrkrslts/op_301_02_03p.xml", opts, data);

    // result값 무조건 save처리
    ds_retrieve.setCellData(0, "odrRmk", result);
    if (retrieve.admitClsCd != 'E') {
        $c.sbm.execute(sbm_saveOdrRmk);
    } else {
        await scwin.f_Retrieve();
    }
};

/**
 * method
 * @name f_Cancel
 * @description 승인 취소
 */
scwin.f_Cancel = async function (gubun) {
    let retrieve = ds_retrieve.getRowJSON(0);
    if (gubun == "1") {
        if (await $c.win.confirm(scwin.MSG_OP_CFM_001)) {
            if (!ds_retrieve.getModifiedIndex().length) {
                //asis는 모든 변경사항이 없으면 서비스를 호출하지 않는다.
                scwin.sbm_cancel_submitdone({ responseJSON: {} });
                return;
            }
            if (ed_vsslNm.getValue() != "") {
                ed_vsslCd.setValue(retrieve.vsslCd);
                ed_vsslNm.setValue(retrieve.vsslNm);
                ds_retrieve.setCellData(0, "vsslNm", retrieve.vsslCd);
            }
            $c.sbm.execute(sbm_cancel);
        }
    } else if (gubun == "2") {
        ds_ExportOnRequest1.removeAll();
        let matched = ds_ExportOnRequest.getMatchedJSON("gridChkBox", "1", true);
        if (!matched.length) {
            await $c.gus.cfAlertMsg("승인취소내역을 선택하여 주십시오.");
            return;
        }

        if (matched.length == ds_ExportOnRequest.getRowCount()) {
            await $c.gus.cfAlertMsg("전체승인취소 버튼을 이용하여 주십시오.");
            ds_ExportOnRequest.undoAll();
            ds_ExportOnRequest1.removeAll();
            return;
        }

        matched = matched.map((item) => {
            return {
                "selfTransClntNo": item.selfTransClntNo,
                "onReqNo": item.onReqNo,
                "odrNo": item.odrNo,
                "cntrSeq": item.cntrSeq,
                "odrWrkPathSeq": item.odrWrkPathSeq,
                "odrWrkStpSeq": item.odrWrkStpSeq,
                "nrm": item.nrm,
            };
        });
        ds_ExportOnRequest1.setJSON(matched);

        //pcy
        if (ed_vsslNm.getValue() != "") {
            ed_vsslCd.setValue(retrieve.vsslCd);
            ed_vsslNm.setValue(retrieve.vsslNm);
        }

        if (acb_admitClsCd2.getValue() == 'Y') {
            ds_retrieve.setCellData(0, "prebilgYn", 1);
        } else {
            ds_retrieve.setCellData(0, "prebilgYn", 0);
        }

        if ($c.gus.cfIsNull(retrieve.odrNo)) {
            if (retrieve.lineCd == "SKR" && $c.gus.cfIsNull(acb_admitClsCd2.getValue())) {
                await $c.win.alert("SKR라인 수출상차요청 승인시에는 반드시 선수납 대상 여부를 기재해야 합니다.");
                return false;
            }
        }

        if (await $c.win.confirm(MSG_CM_CRM_011)) {
            $c.sbm.execute(sbm_cancel2);
        }
    }
};

/**
 * method
 * @name f_RowCopy
 * @description 행 복사
 */
scwin.f_RowCopy = function (row, colid, value) {
    let rowObj = ds_ExportOnRequest.getRowJSON(row);
    if (value === undefined) {
        value = rowObj[colid];
    }
    for (let idx = 0; idx < ds_ExportOnRequest.getRowCount(); idx++) {
        ds_ExportOnRequest.setCellData(idx, colid, value);
        switch (colid) {
            case "onWrkPlNm":
                ds_ExportOnRequest.setCellData(idx, "onWrkPlCd", rowObj.onWrkPlCd);
                break;

            case "onWrkPlCd":
                ds_ExportOnRequest.setCellData(idx, "onWrkPlNm", rowObj.onWrkPlNm);
                break;

            case "rtrnWrkPlNm":
                ds_ExportOnRequest.setCellData(idx, "rtrnWrkPlCd", rowObj.rtrnWrkPlCd);
                break;

            case "rtrnWrkPlCd":
                ds_ExportOnRequest.setCellData(idx, "rtrnWrkPlNm", rowObj.rtrnWrkPlNm);
                break;
        }
    }
};

