/**
 * event
 * @name sbm_retrieve_submitdone
 * @description
 */
scwin.sbm_retrieve_submitdone = async function (e) {
    if (e.responseJSON?.resultDataSet?.length && e.responseJSON.resultDataSet[0].Code == -1) {
        return;
    }
    let retrieve = ds_retrieve.getRowJSON(0);
    if ($c.gus.cfIsNull((retrieve.odrNo))) {
        acb_admitClsCd2.setValue("");
    } else {
        if ($c.gus.cfIsNull((retrieve.prebilgYn))) {
            acb_admitClsCd2.setValue("");
        } else if (retrieve.prebilgYn == 1) {
            acb_admitClsCd2.setValue("Y");
        } else {
            acb_admitClsCd2.setValue("");
        }
    }

    scwin.bf_admitClsCd = retrieve.admitClsCd;
    if (!$c.gus.cfIsNull(retrieve.masterKey)) {
        grp_master.show("");
        tbx_master.setValue("Master Key [" + retrieve.masterKey + "]로 진행중인 건입니다...현재 이번주 소진개수를 필히 확인하시기 바랍니다.(click!!)");
    } else {
        grp_master.hide();
        tbx_master.setValue("");
    }

    //for=ds_retrieve
    const v_lineCd = retrieve.lineCd;
    if (!ds_retrieve.getRowCount()) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_003);
    } else {
        ds_retrieve.setRowPosition(0);
        if (retrieve.odrNo == "") {
            $c.gus.cfDisableObjects([btn_save, btn_cancel, btn_cancel2]);
        } else {
            $c.gus.cfEnableObjects([btn_save]);
            if (retrieve.admitClsCd == "O") {
                $c.gus.cfEnableObjects([btn_cancel, btn_cancel2]);
            } else if (retrieve.admitClsCd == "C") {
                gr_exportOnRequest.setReadOnly("grid", true);
            }
        }
        // WJS 라인 C6 오더 이면 자가가 신청시 입력한VANTERM 과 담당자가 생성시 입력한 VANTERM 을 비교
        if (v_lineCd == "WJS") {
            if (retrieve.odrNo.substring(1, 3) == "C6" || retrieve.odrNo.substring(1, 3) == "C4") {
                $c.gus.cfDisableObjects([acb_jeVanTermCd, acb_liVanTermCd]);
            } else {
                $c.gus.cfDisableObjects([acb_jeVanTermCd]);
            }
            grp_vanTerm.show("");
            // WJS 외의 라인 은 VANTERM은 hidden
        } else {
            grp_vanTerm.hide();
        }

        if ((v_lineCd == "WHL" || v_lineCd == "IAL") && retrieve.lane != "KSI") {
            gr_exportOnRequest.setReadOnly("grid", true);
        }

        //TS라인의 경우 BOOKING정보를 가져옴
        //SITC PRISM OPEN ( NOLS , SOFC , TCLC ) Added, 2014.09.22 TMSC라인 추가 20160315 MAS라인추가
        switch (v_lineCd) {
            case "TSL":
            case "SITC":
            case "SKR":
            case "NOLS":
            case "SOFC":
            case "TCLC":
            case "TMSC":
            case "TJM":
            case "MAS":
            case "JJS":
            case "APL":
            case "DWH":
            case "COS":
            case "MOL":
            case "RHT":
            case "ONE":
                //조회조건값 셋팅
                dma_cndInfo.set("lineCd", v_lineCd);
                dma_cndInfo.set("bookingNo", retrieve.bookingNo);
                if (dma_cndInfo.get("bookingNo") != "") {
                    let ret = await $c.sbm.execute(sbm_bkRetrieve);
                    if (ret.responseJSON.resultDataSet[0].Msg == "SUCC") {
                        scwin.sbm_bkRetrieve_submitdone();
                    } else {
                        scwin.sbm_bkRetrieve_submiterror();
                    }
                }
                break;

            default:
                //테이블 숨김
                trBookingInfo2.hide();
                break;
        }

        //pcy
        if (v_lineCd == "TSL" || v_lineCd == "SITC") {
            ed_vsslCd.setValue(retrieve.vsslCd);
            ed_vsslNm.setValue(retrieve.vsslNm);
            ed_portcnt.setValue(retrieve.portcnt);
        }
    }

    //for=ds_ExportOnRequest
    if (retrieve.odrNo == "" && retrieve.admitClsCd == "S") {
        gr_exportOnRequest.setReadOnly("grid", false);
        $c.gus.cfEnableObjects([btn_crtOdr]);

        let cntrSeq = 1;
        //오더가 생성되지 않았으면 상차요청한데이타를 가지고 기본 정보를 생성한 후 오더를 생성한다.
        let addDataArr = [];
        for (let item of ds_ExportOnRequestEachCnt.getAllJSON()) {
            const reqQty = $c.num.parseInt(item.reqQty, 0);
            for (let j = 0; j < reqQty; ++j) {
                let data = {
                    "selfTransClntNo": retrieve.selfTransClntNo,
                    "onReqNo": retrieve.onReqNo,
                    "onReqGoodsSeq": 0,
                    "nrm": item.cntrSizCd + item.cntrTypCd + "E",
                    "lineCd": v_lineCd,
                    "bookingNo": retrieve.bookingNo,
                    "odrNo": retrieve.odrNo,
                    "admitCnt": 1,
                    "gubun": "0",
                    "closingTime": retrieve.closingTime,
                    "cnt": 1,
                    "sellAmt": "0",
                    "dsSellAmt": "0",
                    "dcsnClsCd": "N",
                    "dpctYn": retrieve.dpctYn,
                    "cntrSeq": cntrSeq,
                };

                if (!$c.gus.cfIsNull(item.onWrkPlCd) || item.onWrkPlCd != "") {
                    data.onWrkPlCd = item.onWrkPlCd;
                    data.onWrkPlNm = item.onWrkPlNm;
                }

                if (retrieve.pickuprgnCd == "EWY") {
                    data.onWrkPlCd = "4C02";
                    data.onWrkPlNm = "의왕CY";
                    data.onIntendDt = scwin.strCurDate;
                    data.crryinIntendPrdDt = scwin.strCurDate;
                    //반납지 line에 따라 자동 셋팅(의왕)
                    switch (v_lineCd) {
                        case "TSL":
                        case "CQH":
                        case "NOLS":
                        case "SWIL":
                        case "MSN":
                        case "KYW":
                            data.rtrnWrkPlCd = "6C01";
                            data.rtrnWrkPlNm = "신선대동부CY";
                            break;

                        case "HSD":
                        case "COH":
                        case "RCL":
                            data.rtrnWrkPlCd = "6T987";
                            data.rtrnWrkPlNm = "부산타CY";
                            break;

                        case "SITC":
                            data.rtrnWrkPlCd = "6C09";
                            data.rtrnWrkPlNm = "DPCTCY";
                            break;

                        case "TA":
                        case "WW":
                        case "GBH":
                        case "TCLC":
                            data.rtrnWrkPlCd = "6C16";
                            data.rtrnWrkPlNm = "2부두CY";
                            break;

                        case "ESL":
                            data.rtrnWrkPlCd = "6P26";
                            data.rtrnWrkPlNm = "한진신항T";
                            break;

                        default:
                            data.rtrnWrkPlCd = "6P10";
                            data.rtrnWrkPlNm = "동부감만T";
                            break;
                    }
                } else if (retrieve.pickuprgnCd == "PUS") {	//부산 경우 수출상차요청내역 자동세팅	20191118 김한수k
                    data.onWrkPlCd = "6C01";
                    data.onWrkPlNm = "동원로엑스신선대CY";
                    data.onIntendDt = scwin.strCurDate;
                    data.crryinIntendPrdDt = scwin.strCurDate;
                    data.rtrnWrkPlCd = "6C01";
                    data.rtrnWrkPlNm = "동원로엑스신선대CY";
                }

                //TSL 하차지 자동변경( 선사EDI기준 USOAK,USLGB 일때 6P12 로 하차지 자동변경건)
                if (v_lineCd == "TSL") {
                    if (ds_bookingInfo.getCellData(0, "dchrPortCd") == "USOAK" || ds_bookingInfo.getCellData(0, "dchrPortCd") == "USLGB") {
                        data.rtrnWrkPlCd = "6P12";
                        data.rtrnWrkPlNm = "HBCT";
                    }
                }

                if (tbx_odrNo.getValue() == "") {
                    if (rd_dpctYn.getValue() == "1") {
                        data.onWrkPlCd = "6P10";
                        data.onWrkPlNm = "동부감만T";
                        data.rtrnWrkPlCd = "6P10";
                        data.rtrnWrkPlNm = "동부감만T";
                        data.onIntendDt = scwin.nowDt;
                        data.crryinIntendPrdDt = scwin.nextDt;
                    } else {
                        if (v_lineCd == "SKR") {
                            data.onWrkPlCd = "6C24";
                            data.onWrkPlNm = "신영감만CY";
                            data.rtrnWrkPlCd = "6C24";
                            data.rtrnWrkPlNm = "신영감만CY";
                            data.onIntendDt = scwin.nowDt;
                            data.crryinIntendPrdDt = scwin.nextDt;
                        }
                    }
                }
                addDataArr.push(data);
                cntrSeq++;
            }//for
        }//for
        ds_ExportOnRequest.insertJSON(ds_ExportOnRequest.getRowCount(), addDataArr);
    } else {
        // $c.gus.cfEnableObjects([grp_data1, grp_data2, grp_data3]);
        gr_exportOnRequest.setReadOnly("grid", false);
        $c.gus.cfDisableObjects([btn_crtOdr]);
    }

    if (ds_ExportOnRequest.getRowCount()) {
        gr_exportOnRequest.setFocusedCell(0, 0, false);
    }
};

