/**
 * event
 * @name acb_admitClsCd_onviewchange
 * @description
 */
scwin.acb_admitClsCd_onviewchange = function (info) {
    switch (acb_admitClsCd.getValue()) {
        case "O":
            if (ds_retrieve.getCellData(0, "odrNo") == "") {
                $c.gus.cfEnableObjects([btn_crtOdr]);
            } else {
                $c.gus.cfEnableObjects([btn_save]);
            }
            gr_exportOnRequest.setReadOnly("grid", false);
            break;
        case "R":
            $c.gus.cfEnableObjects([btn_crtOdr, btn_save]);
            gr_exportOnRequest.setReadOnly("grid", false);
            break;
        case "C":
            $c.gus.cfDisableObjects([btn_crtOdr]);
            $c.gus.cfEnableObjects([btn_save]);
            gr_exportOnRequest.setReadOnly("grid", true);
            break;
        case "S":
            $c.gus.cfDisableObjects([btn_crtOdr, btn_save]);
            gr_exportOnRequest.setReadOnly("grid", false);
            break;
        case "E":
            $c.gus.cfDisableObjects([btn_crtOdr]);
            $c.gus.cfEnableObjects([btn_save]);
            gr_exportOnRequest.setReadOnly("grid", false);
            break;
    }
};

/**
 * event
 * @name gr_exportOnRequest_onexit
 * @description OnExit(row,colid,olddata)
 */
scwin.gr_exportOnRequest_onexit = function (row, col, value) {
    value = value.trim();
    const colid = gr_exportOnRequest.getColumnID(col);
    switch (colid) {
        case "onIntendDt":
        case "crryinIntendPrdDt":
            scwin.f_RowCopy(row, colid, value);
            break;

        case "admitCnt":
            scwin.f_limitCnt(row);
            break;
    }
};

/**
 * event
 * @name gr_exportOnRequest_onviewchange
 * @description
 */
scwin.gr_exportOnRequest_onviewchange = function (info) {
    const row = info.rowIndex;
    const value = info.newValue.trim();
    const colid = info.colId;
    switch (colid) {
        case "onWrkPlCd":
            if (info.oldValue == value) {
                return;
            }
            ds_ExportOnRequest.setCellData(row, "onWrkPlCd", value);
            ds_ExportOnRequest.setCellData(row, "onWrkPlNm", "");	//상차지
            if (value == "") {
                scwin.f_RowCopy(row, colid, value);
                return;
            }
            scwin.gr_exportOnRequest_onpopup(row, "onWrkPlNm");
            break;

        case "onWrkPlNm":
            if (info.oldValue == value) {
                return;
            }
            ds_ExportOnRequest.setCellData(row, "onWrkPlNm", value);
            ds_ExportOnRequest.setCellData(row, "onWrkPlCd", "");	//상차지
            if (value == "") {
                scwin.f_RowCopy(row, colid, value);
                return;
            }
            scwin.gr_exportOnRequest_onpopup(row, "onWrkPlNm");
            break;

        case "rtrnWrkPlCd":
            if (info.oldValue == value) {
                return;
            }
            ds_ExportOnRequest.setCellData(row, "rtrnWrkPlCd", value);
            ds_ExportOnRequest.setCellData(row, "rtrnWrkPlNm", "");	//반납지
            if (value == "") {
                scwin.f_RowCopy(row, colid, value);
                return;
            }
            scwin.gr_exportOnRequest_onpopup(row, "rtrnWrkPlNm");
            break;

        case "rtrnWrkPlNm":
            if (info.oldValue == value) {
                return;
            }
            ds_ExportOnRequest.setCellData(row, "rtrnWrkPlNm", "value");
            ds_ExportOnRequest.setCellData(row, "rtrnWrkPlCd", "");	//반납지
            if (value == "") {
                scwin.f_RowCopy(row, colid, value);
                return;
            }
            scwin.gr_exportOnRequest_onpopup(row, "rtrnWrkPlNm");
            break;
    }
};

/**
 * event
 * @name gr_exportOnRequest_onpopup
 * @description OnPopup(row,colid,data)
 */
scwin.gr_exportOnRequest_onpopup = function (row, colid, value) {
    let pName;
    let pCode;

    switch (colid) {
        case "onWrkPlNm":
            scwin.currentRow = row;
            pCode = ds_ExportOnRequest.getCellData(row, "onWrkPlCd");
            pName = ds_ExportOnRequest.getCellData(row, "onWrkPlNm");
            ds_ExportOnRequest.setCellData(row, "onWrkPlCd", "");
            ds_ExportOnRequest.setCellData(row, "onWrkPlNm", "");
            scwin.f_RowCopy(row, "onWrkPlCd", "");
            udc_WrkPl.cfCommonPopUp(scwin.udc_WrkPl_onWrkPl_popup_callback, pCode, pName, "T", null, "상차지코드, 상차지명", null, null, null, null, null, null, null, null, null, "상차지조회,상차지코드,상차지명");
            break;

        case "rtrnWrkPlNm":
            scwin.currentRow = row;
            // 반납지 Popup
            pCode = ds_ExportOnRequest.getCellData(row, "rtrnWrkPlCd");
            pName = ds_ExportOnRequest.getCellData(row, "rtrnWrkPlNm");
            ds_ExportOnRequest.setCellData(row, "rtrnWrkPlNm", "");
            ds_ExportOnRequest.setCellData(row, "rtrnWrkPlCd", "");
            scwin.f_RowCopy(row, "rtrnWrkPlCd", "");
            udc_WrkPl.cfCommonPopUp(scwin.udc_WrkPl_rtrnWrkPl_popup_callback, pCode, pName, "T", null, null, null, null, null, null, null, null, null);
            break;

        case "admitCnt":
            scwin.f_limitCnt(row);
            break;
    }
};

/**
 * method
 * @name udc_WrkPl_onWrkPl_popup_callback
 * @description 팝업 콜백
 * @param {Array} rtnList
 */
scwin.udc_WrkPl_onWrkPl_popup_callback = function (rtnList) {
    $c.gus.cfSetGridReturnValue(rtnList, ds_ExportOnRequest, scwin.currentRow, "onWrkPlCd", "onWrkPlNm");
    scwin.f_RowCopy(scwin.currentRow, "onWrkPlCd");
};

/**
 * method
 * @name udc_WrkPl_rtrnWrkPl_popup_callback
 * @description 팝업 콜백
 * @param {Array} rtnList
 */
scwin.udc_WrkPl_rtrnWrkPl_popup_callback = function (rtnList) {
    $c.gus.cfSetGridReturnValue(rtnList, ds_ExportOnRequest, scwin.currentRow, "rtrnWrkPlCd", "rtrnWrkPlNm");
    scwin.f_RowCopy(scwin.currentRow, "rtrnWrkPlCd");
};

/**
 * event
 * @name gr_exportOnRequest_oncellclick
 * @description
 */
scwin.gr_exportOnRequest_oncellclick = async function (row, col, colid) {
    if (colid == "gridChkBox") {
        const rowObj = ds_ExportOnRequest.getRowJSON(row);
        if (rowObj.gridChkBox == "1") {
            if (!$c.gus.cfIsNull(rowObj.cntrNo)) {
                await $c.gus.cfAlertMsg("이미 실적이 발생하여 취소할 수 없습니다.");
                ds_ExportOnRequest.undoRow(row);
                return;
            }
        }
    }
};

