/**
 * event
 * @name btn_srchOnReqNo_onclick
 * @description
 */
scwin.btn_srchOnReqNo_onclick = async function (e) {
    let data = {
        param: "O;" + ed_srchSelfTransCoCd.getValue(),   //수출입구분 + 차
    };
    //상차요청번호 Pop up
    let opts = {
        id: "op_301_02_04p2_popup",
        popupName: "상차요청번호",
        modal: true,
        type: "browserPopup",  //화면 오픈 타입 ("pageFramePopup", "browserPopup")
        title: "Win pop",  //Layer pop
        width: 600,
        height: 540,
    };

    let rtnList = await $c.win.openPopup("/ui/ds/op/wrkrslts/cywrkrslts/op_301_02_04p2.xml", opts, data);
    if (rtnList != null) {
        ed_srchOnReqNo.setValue(rtnList[0]);	//상차요청번호
    } else {
        ed_srchOnReqNo.setValue("");	//상차요청번호
    }
};

